    'footer.home':'Strona główna','footer.about':'O nas','footer.references':'Referencje','footer.contact':'Kontakt',
    'footer.copyright':'© 2022 INTERY d.o.o. Wszelkie prawa zastrzeżone. Zarejestrowana w Słowenii.',
